private struct FichiersTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum FichiersScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("fichier") || t.contains("file") || t.contains("offline") || t.contains("home"):
            FichiersFilesScreen()
        case let t where t.contains("recent") || t.contains("récent") || t.contains("account") || t.contains("compte"):
            FichiersAccountScreen()
        default:
            FichiersGenericListScreen(title: tab)
        }
    }
}
