private struct FichiersFilesScreen: View {
    var body: some View {
        NavigationStack {
            List(FichiersDemoData.files) { f in
                HStack(spacing: 12) {
                    Image(systemName: f.isFolder ? "folder.fill" : "doc.fill").foregroundStyle(FichiersTokens.dbxBlue).font(.title2)
                    VStack(alignment: .leading) { Text(f.name).font(.body); Text(f.detail).font(.caption).foregroundStyle(.secondary) }
                    Spacer()
                    if f.isFolder { Image(systemName: "chevron.right").foregroundStyle(.tertiary) }
                }
            }.navigationTitle("Fichiers")
        }
    }
}

